DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "PGlateximage.pl", "contextFraction.pl", "Pd.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ Context("LimitedFraction")->flags->set( allowMixedNumbers => 0, reduceConstants => 1, showMixedNumbers => 0 ); Parser::Number::NoDecimals; $d = list_random(3 .. 10); ($d, $n) = random_coprime([$d], [$d+1, 2*$d - 1]); $frac = Fraction($n, $d); $xmin = -3/$d; $xmax = 2+3/$d; $inc = $xmin + 1/$d;
$image_1 = createLaTeXImage(); $image_1->addToPreamble(latexImagePreamble()); $image_1->BEGIN_LATEX_IMAGE \begin{tikzpicture} \begin{axis}[ numberline, xmin=$xmin, xmax=$xmax, xtick={0,1,2}, minor xtick={$xmin,$inc,...,$xmax}, ] \addplot[soliddot] coordinates {($frac, 0)}; \end{axis} \end{tikzpicture}
END_LATEX_IMAGE
############################################################ # Body ############################################################
BEGIN_PGML What fraction is represented on the numberline?
>> [@image(insertGraph($image_1), width=>600)@]* <<
[_]{$frac}{6}
END_PGML
